function solve(nums) {
    let maxSum = 0;
    const n = nums.length;

    // Iterate all possible masks for A and B (each bit represents if the element is in A or B)
    // Since each element can be in A, B, or C, we need 2 bits per element
    // But with n up to 19, it's not feasible to iterate all 3^19 possibilities
    // So we need a smarter approach

    // Since n is small (<=19), we can try all possible non-empty B subsets
    // For each B, we can compute AND(B), and then optimally assign remaining elements to A and C to maximize XOR(A) + XOR(C)
    // The optimal assignment for remaining elements is to put each element either in A or C, whichever gives higher contribution

    for (let mask = 0; mask < (1 << n); mask++) {
        let B = [];
        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                B.push(nums[i]);
            }
        }
        let andB = 0;
        if (B.length > 0) {
            andB = B[0];
            for (let i = 1; i < B.length; i++) {
                andB &= B[i];
            }
        }

        // Remaining elements are not in B, they can be in A or C
        let xorA = 0;
        let xorC = 0;
        for (let i = 0; i < n; i++) {
            if (!(mask & (1 << i))) {
                // Element is not in B, choose to put in A or C to maximize the sum
                const num = nums[i];
                if ((xorA ^ num) + xorC > xorA + (xorC ^ num)) {
                    xorA ^= num;
                } else {
                    xorC ^= num;
                }
            }
        }
        const currentSum = xorA + andB + xorC;
        if (currentSum > maxSum) {
            maxSum = currentSum;
        }
    }

    return maxSum;
}

